/**
 * @method 
 * @name f_mainModify 
 * @description Main저장 버튼 클릭
 */
scwin.f_mainSave = async function () {
  const dsMain9Data = ds_main9.getRowJSON(0);
  if (ds_main2.getRowCount() == 0) {
    await $c.gus.cfAlertMsg($p, "%1할(된) %2이(가) 존재하지 않습니다.", ["작성(변경)", " 일일 작업계획"]);
    return false;
  }
  ;

  // 검색조건 필수 입력 체크
  // 본선관리번호, 작업일자
  const validDateTime = await $c.gus.cfValidate($p, [ica_wrkStDt, ed_wrkStHh, ica_wrkEndDt, ed_wrkEndHh]);
  if (!validDateTime) return;
  if (ed_wrkStHh.getValue().length != 4) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_055, ["시간형식"]);
    ed_wrkStHh.focus();
    return false;
  }
  ;
  if (ed_wrkEndHh.getValue().length != 4) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_055, ["시간형식"]);
    ed_wrkEndHh.focus();
    return false;
  }
  ;
  if (ed_wrkStHh.getValue().slice(0, 2) > "23") {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_021, ["작업시간"]); // "@은(는) 시가 잘못되었습니다."
    ed_wrkStHh.focus();
    return;
  }
  ;
  if (ed_wrkStHh.getValue().slice(2, 4) > "59") {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_022, ["작업시간"]); // "@은(는) 분이 잘못되었습니다."
    ed_wrkStHh.focus();
    return;
  }
  ;
  if (ed_wrkEndHh.getValue().slice(0, 2) > "24") {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_022, ["작업시간"]); // "@은(는) 시가 잘못되었습니다."
    ed_wrkEndHh.focus();
    return;
  }
  ;
  if (ed_wrkEndHh.getValue().slice(0, 2) == "00" && ed_wrkEndHh.getValue().slice(2, 4) == "00") {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_022, ["작업시간"]); // "@은(는) 분이 잘못되었습니다."
    ed_wrkEndHh.focus();
    return;
  }
  ;
  if (ed_wrkEndHh.getValue().slice(0, 2) == "24" && ed_wrkEndHh.getValue().slice(2, 4) > "00") {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_022, ["작업시간"]); // "@은(는) 분이 잘못되었습니다."
    ed_wrkEndHh.focus();
    return;
  }
  ;
  if (ed_wrkEndHh.getValue().slice(2, 4) > "59") {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_022, ["작업시간"]); // "@은(는) 분이 잘못되었습니다."
    ed_wrkEndHh.focus();
    return;
  }
  ;
  if (ica_wrkStDt.getValue() < dsMain9Data.wrkStDt || ica_wrkStDt.getValue() > $c.date.addDate($p, dsMain9Data.wrkStDt, 1)) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_030 + "Shift별 기준작업일자로부터 하루이후까지만 가능합니다", ["야간/심야의 작업시작일자"]);
    ica_wrkStDt.focus();
    return;
  }
  ;
  if (ica_wrkEndDt.getValue() == $c.date.addDate($p, dsMain9Data.wrkStDt, 1)) {
    if (ed_wrkEndHh.getValue() > '0700') {
      await $c.gus.cfAlertMsg($p, "야간/심야의 작업종료시간은 07시 이전이어야 합니다.");
      ed_wrkEndHh.focus(); // 시작시간에 focus
      return;
    }
    ;
  }
  ;
  if (!$c.gus.cfIsAfterDate($p, ica_wrkStDt.getValue(), ica_wrkEndDt.getValue())) {
    // 시작일자와 종료일자 비교하여 시작일자보다 종료일자가 크지 않도록 Check
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
    ica_wrkStDt.focus(); // 시작일자에 focus
    return;
  }
  ;
  if (ica_wrkStDt.getValue() == ica_wrkEndDt.getValue()) {
    // 시작일자와 종료일자가 동일할때
    if (!$c.gus.cfIsAfterDate($p, ed_wrkStHh.getValue(), ed_wrkEndHh.getValue())) {
      await $c.gus.cfAlertMsg($p, MSG_CM_ERR_058); // 시작시간이 종료시간 이전이어야 합니다.
      ed_wrkStHh.focus(); // 시작시간에 focus
      return;
    }
    ;
  }
  ;
  let sbmObj = await $c.sbm.execute($p, sbm_main);
  if (sbmObj.responseJSON.resultDataSet[0].Msg == "SUCC") {
    await scwin.sbm_main_submitdone(sbmObj);
  }
  ;
};

